#include <stdio.h>
#include <stdlib.h>
#include <string.h>

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N;
        scanf("%d", &N);
        long long L[N];
        for (int i = 0; i < N; i++) {
            scanf("%lld", &L[i]);
        }
        long long A, B, C;
        scanf("%lld %lld %lld", &A, &B, &C);
        char S[N + 1];
        scanf("%s", S);
        for (int i = 0; i < N; i++) {
            if (S[i] == 'R') {
                int left = i;
                int right = N - 1;
                while (left < right) {
                    long long temp = L[left];
                    L[left] = L[right];
                    L[right] = temp;
                    left++;
                    right--;
                }
            } else if (S[i] == 'A') {
                for (int j = i; j < N; j++) {
                    L[j] += A;
                }
            } else if (S[i] == 'M') {
                for (int j = i; j < N; j++) {
                    L[j] *= B;
                }
            }
            for (int j = i; j < N; j++) {
                L[j] %= C;
            }
            printf("%lld", L[i]);
            if (i < N - 1) {
                printf(" ");
            }
        }
        printf("\n");
    }
    return 0;
}

