            String S = sc.next();
            for (int i = 0; i < N; i++) {
                if (S.charAt(i) == 'R') {
                    int left = i;
                    int right = N - 1;
                    while (left < right) {
                        long temp = L[left];
                        L[left] = L[right];
                        L[right] = temp;
                        left++;
                        right--;
                    }
                } else if (S.charAt(i) == 'A') {
